DROP TABLE IF EXISTS `kr_area`;
CREATE TABLE `kr_area` (
  `id` int(11) NOT NULL,
  `parent_id` int(11) NOT NULL,
  `name` varchar(255) NOT NULL,
  `merger_name` varchar(255) NOT NULL,
  `short_name` varchar(255) NOT NULL,
  `merger_short_name` varchar(255) NOT NULL,
  `level_type` varchar(255) NOT NULL,
  `city_code` varchar(255) DEFAULT '',
  `zip_code` varchar(255) DEFAULT '',
  `pinyin` varchar(255) NOT NULL,
  `jianpin` varchar(255) NOT NULL,
  `first_char` varchar(255) NOT NULL,
  `lng` varchar(255) NOT NULL,
  `lat` varchar(255) NOT NULL,
  `remarks` varchar(255) DEFAULT '',
  `company_id` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COMMENT='地区表';

