-- ----------------------------
-- Table structure for kr_member
-- ----------------------------
DROP TABLE IF EXISTS `kr_member`;
CREATE TABLE `kr_member` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `uid` varchar(255) NOT NULL,
  `name` varchar(255) DEFAULT '' COMMENT '姓名',
  `mobile` varchar(255) DEFAULT '' COMMENT '手机号',
  `gender` varchar(255) NOT NULL COMMENT '1：男 2：女',
  `birthYear` varchar(255) NOT NULL COMMENT '出生年份',
  `height` varchar(255) NOT NULL COMMENT '身高',
  `education` varchar(255) NOT NULL COMMENT '学历',
  `industry` varchar(255) NOT NULL COMMENT '工作类型',
  `occupation` varchar(255) DEFAULT '' COMMENT '工作岗位',
  `albumKeys` varchar(255) DEFAULT '' COMMENT '照片ID',
  `annualIncome` decimal(10,0) NOT NULL COMMENT '年收入',
  `hasHouse` int(11) NOT NULL COMMENT '是否有房',
  `houseCount` int(11) NOT NULL,
  `hasVehicle` int(11) NOT NULL COMMENT '是否有车',
  `currentAddress` varchar(255) NOT NULL COMMENT '现居住地',
  `permanentAddress` varchar(255) NOT NULL COMMENT '老家',
  `familys` varchar(255) DEFAULT '',
  `maritalStatus` varchar(255) NOT NULL COMMENT '婚况',
  `hasChildren` int(11) NOT NULL COMMENT '是否有孩子',
  `childrens` varchar(255) NOT NULL COMMENT '有无孩子',
  `remark` text COMMENT '备注',
  `vipLevel` varchar(255) NOT NULL COMMENT '1：普通会员 2：付费会员',
  `employee_id` int(11) NOT NULL COMMENT '创建的管理员ID',
  `create_time` int(11) NOT NULL,
  `update_time` int(11) NOT NULL,
  `delete_time` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`,`uid`)
) ENGINE=MyISAM AUTO_INCREMENT=465 DEFAULT CHARSET=utf8;

-- ----------------------------
-- Records of kr_member
-- ----------------------------

